const { promisify } = require('util');

function legacy(value, callback) {
  if (value < 0) {
    callback(new Error('negative'));
  } else {
    callback(null, value * 2);
  }
}

const promisified = promisify(legacy);

promisified(5)
  .then(result => console.log('A:', result))
